482→  async handleIncomingMessage(baileysMsg) {
483→    try {
484→      if (!baileysMsg?.key?.remoteJid) return;
485→      if (baileysMsg.key.remoteJid === "status@broadcast") return;
486→
487→      const chatJid = baileysMsg.key.remoteJid;
488→      const messageId = baileysMsg.key.id || `${Date.now()}`;
489→      if (this.shouldSkipAsDuplicate(chatJid, messageId)) {
490→        this.logger.info(
491→          `Skipping duplicate event for message ${messageId} in ${chatJid}.`,
492→        );
493→        return;
494→      }
495→
496→      const normalizedMessage = unwrapMessageContainer(baileysMsg.message);
497→      const text = extractTextContent(baileysMsg.message);
498→
499→      if (baileysMsg.key.fromMe) {
500→        if (!this.config.app.singleNumberMode) {
501→          this.logger.info(
502→            `Skipping fromMe message ${messageId} from ${chatJid} because SINGLE_NUMBER_MODE=false.`,
503→          );
504→          return;
505→        }
506→        if (this.shouldSkipFromMeEcho(chatJid, messageId, text)) {
507→          this.logger.info(
508→            `Loop guard blocked bot-echo fromMe message ${messageId} in ${chatJid}.`,
509→          );
510→          return;
511→        }
512→        this.logger.info(
513→          `Accepted fromMe operator message ${messageId} in ${chatJid} (single-number mode).`,
514→        );
515→      }
516→
517→      const attachments = await this.extractAttachments(
518→        baileysMsg,
519→        normalizedMessage,
520→      );
521→
522→      this.logger.info(
523→        `Inbound message accepted from ${baileysMsg.key.remoteJid} (fromMe=${Boolean(baileysMsg.key.fromMe)} textPreview="${textPreview(text)}" attachments=${attachments.length}).`,
524→      );
525→
526→      const input = {
527→        userId: chatJid,
528→        messageId,
529→        text,
530→        attachments,
531→        timestamp: new Date(
532→          Number(baileysMsg.messageTimestamp || Math.floor(Date.now() / 1000)) *
533→            1000,
534→        ).toISOString(),
535→      };
536→
537→      const startedAt = Date.now();
538→      this.logger.info(
539→        `Agent handling started for message ${messageId} in ${chatJid}.`,
540→      );
541→      const result = await withTimeout(
542→        this.agent.handleIncoming(input),
543→        this.config.app.agentTimeoutMs,
544→        "agent.handleIncoming",
545→      );
546→      this.logger.info(
547→        `Agent handling completed for message ${messageId} in ${Date.now() - startedAt}ms.`,
548→      );
549→      if (result?.replyText) {
550→        const routed = await this.sendReplyWithRouting({
551→          incomingJid: chatJid,
552→          inboundMessageId: messageId,
553→          replyText: result.replyText,
554→          fromMe: Boolean(baileysMsg.key.fromMe),
555→        });
556→        this.logger.info(
557→          `Reply sent for message ${messageId}. outId=${routed?.outboundId || "unknown"} target=${routed?.targetJid || chatJid} usedFallback=${Boolean(routed?.usedFallback)} verified=${routed?.verified !== false}.`,
558→        );
559→      } else {
560→        this.logger.warn(
561→          `Agent returned empty reply for message ${messageId}; sending fallback guidance.`,
562→        );
563→        const fallbackText =
564→          "I could not produce a response for that message. Please rephrase your request in one sentence.";
565→        await this.sendReplyWithRouting({
566→          incomingJid: chatJid,
567→          inboundMessageId: messageId,
568→          replyText: fallbackText,
569→          fromMe: Boolean(baileysMsg.key.fromMe),
570→        });
571→      }
572→    } catch (error) {
573→      this.logger.error(`Message handling failed: ${error.message}`);
574→      try {
575→        const chatJid = baileysMsg?.key?.remoteJid;
576→        const inboundId = baileysMsg?.key?.id || `${Date.now()}`;
577→        if (!chatJid) return;
578→        const errorText =
579→          "I encountered an internal error while processing your request. Please try again.";
580→        await this.sendReplyWithRouting({
581→          incomingJid: chatJid,
582→          inboundMessageId: inboundId,
583→          replyText: errorText,
584→          fromMe: Boolean(baileysMsg?.key?.fromMe),
585→        });
586→      } catch (sendError) {
587→        this.logger.error(`Failed to send error message: ${sendError.message}`);
588→      }
589→    }
590→  }
