592→  async extractAttachments(baileysMsg, normalizedMessage) {
593→    const attachments = [];
594→    if (!normalizedMessage) return attachments;
595→
596→    if (normalizedMessage.imageMessage) {
597→      const buffer = await downloadMediaMessage(
598→        baileysMsg,
599→        "buffer",
600→        {},
601→        { logger: pino({ level: "silent" }) },
602→      );
603→      const imageMime = normalizedMessage.imageMessage.mimetype || "image/jpeg";
604→      const fileName = makeFileNameFromMime(
605→        baileysMsg.key.id || "image",
606→        "image",
607→        imageMime,
608→      );
609→      const targetPath = path.join(this.config.paths.inbox, fileName);
610→      await fs.writeFile(targetPath, buffer);
611→      attachments.push({
612→        type: "image",
613→        path: targetPath,
614→        mime: imageMime,
615→        originalName: fileName,
616→      });
617→    }
618→
619→    if (normalizedMessage.documentMessage) {
620→      const buffer = await downloadMediaMessage(
621→        baileysMsg,
622→        "buffer",
623→        {},
624→        { logger: pino({ level: "silent" }) },
625→      );
626→      const docMime =
627→        normalizedMessage.documentMessage.mimetype ||
628→        "application/octet-stream";
629→      const originalName =
630→        normalizedMessage.documentMessage.fileName ||
631→        makeFileNameFromMime(baileysMsg.key.id || "document", "document", docMime);
632→      const safeName = originalName.replace(/[<>:"/\\|?*\u0000-\u001F]/g, "_");
633→      const targetPath = path.join(
634→        this.config.paths.inbox,
635→        `${compactTimestamp()}_${safeName}`,
636→      );
637→      await fs.writeFile(targetPath, buffer);
638→      attachments.push({
639→        type: "document",
640→        path: targetPath,
641→        mime: docMime,
642→        originalName: originalName,
643→      });
644→    }
645→
646→    return attachments;
647→  }
