 1→import chalk from "chalk";
 2→import fs from "fs";
 3→import path from "path";
 4→import winston from "winston";
 5→import { config } from "./config.js";
 6→
 7→const { combine, timestamp, errors, printf, json } = winston.format;
 8→
 9→function colorLevel(level) {
10→  const normalized = (level || "info").toLowerCase();
11→  if (normalized === "error") return chalk.red(normalized.toUpperCase());
12→  if (normalized === "warn") return chalk.yellow(normalized.toUpperCase());
13→  if (normalized === "debug") return chalk.magenta(normalized.toUpperCase());
14→  return chalk.cyan(normalized.toUpperCase());
15→}
16→
17→const consoleFormat = combine(
18→  timestamp(),
19→  errors({ stack: true }),
20→  printf((entry) => {
21→    const prefix = `${chalk.gray(entry.timestamp)} ${colorLevel(entry.level)}`;
22→    const message = `${entry.message}`;
23→    if (entry.stack) {
24→      return `${prefix} ${message}\n${entry.stack}`;
25→    }
26→    return `${prefix} ${message}`;
27→  }),
28→);
29→
30→const fileFormat = combine(timestamp(), errors({ stack: true }), json());
31→fs.mkdirSync(config.paths.logs, { recursive: true });
32→
33→export const logger = winston.createLogger({
34→  level: config.app.logLevel,
35→  defaultMeta: { service: config.app.name },
36→  transports: [
37→    new winston.transports.Console({ format: consoleFormat }),
38→    new winston.transports.File({
39→      filename: path.join(config.paths.logs, "app.log"),
40→      format: fileFormat,
41→      level: config.app.logLevel,
42→    }),
43→    new winston.transports.File({
44→      filename: path.join(config.paths.logs, "error.log"),
45→      format: fileFormat,
46→      level: "error",
47→    }),
48→  ],
49→});
50→
51→export const auditLogger = winston.createLogger({
52→  level: "info",
53→  defaultMeta: { service: `${config.app.name}-audit` },
54→  format: fileFormat,
55→  transports: [
56→    new winston.transports.File({
57→      filename: path.join(config.paths.logs, "audit.log"),
58→    }),
59→  ],
60→});
61→
62→export function writeAudit(event) {
63→  auditLogger.info("audit_event", event);
64→}
